import { useState, useEffect, useMemo } from "react";
import * as XLSX from "xlsx";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid,
  Tooltip, Legend, ResponsiveContainer, ReferenceLine, Area, AreaChart, ComposedChart
} from "recharts";

const KHULNA_LAT = 22.8098;
const KHULNA_LON = 89.5644;
const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];

function avg(arr) {
  const valid = arr.filter(v => v != null);
  if (!valid.length) return null;
  return parseFloat((valid.reduce((a, b) => a + b, 0) / valid.length).toFixed(1));
}

function groupByMonth(rows) {
  const monthly = {};
  rows.forEach(r => {
    const [year, month] = r.date.split("-");
    const key = `${year}-${month}`;
    if (!monthly[key]) monthly[key] = { label: `${MONTHS[parseInt(month)-1]} ${year}`, maxT: [], minT: [], meanT: [], hum: [], sol: [] };
    if (r.maxTemp != null) monthly[key].maxT.push(r.maxTemp);
    if (r.minTemp != null) monthly[key].minT.push(r.minTemp);
    if (r.meanTemp != null) monthly[key].meanT.push(r.meanTemp);
    if (r.humidity != null) monthly[key].hum.push(r.humidity);
    if (r.solar != null) monthly[key].sol.push(r.solar);
  });
  return Object.entries(monthly).map(([k, v]) => ({
    key: k, label: v.label,
    maxTemp: avg(v.maxT), minTemp: avg(v.minT),
    meanTemp: avg(v.meanT), humidity: avg(v.hum),
    solar: avg(v.sol),
  }));
}

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background:"rgba(10,20,35,0.97)", border:"1px solid #1e4d6b", borderRadius:10, padding:"10px 16px", color:"#e0f4ff", fontSize:13 }}>
      <div style={{ fontWeight:700, marginBottom:6, color:"#7dd3fc" }}>{label}</div>
      {payload.map((p,i) => (
        <div key={i} style={{ color:p.color, marginBottom:2 }}>
          {p.name}: <b>{p.value != null ? p.value : "—"}{p.unit||""}</b>
        </div>
      ))}
    </div>
  );
};

const inputStyle = {
  background: "rgba(255,255,255,0.06)", border: "1px solid #1e4d6b",
  borderRadius: 8, color: "#e0f4ff", padding: "7px 12px",
  fontSize: 13, fontFamily: "Georgia, serif", outline: "none",
  colorScheme: "dark", cursor: "pointer"
};

const btnStyle = (active) => ({
  padding: "6px 13px", borderRadius: 8, border: "1px solid",
  borderColor: active ? "#38bdf8" : "#1e4d6b",
  background: active ? "#0c3a5e" : "transparent",
  color: active ? "#7dd3fc" : "#4a8aaa",
  cursor: "pointer", fontSize: 12, fontFamily: "Georgia, serif", transition: "all 0.15s"
});

export default function KhulnaWeather() {
  const [rawData, setRawData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const todayStr = new Date().toISOString().split("T")[0];
  const [startDate, setStartDate] = useState("2019-01-01");
  const [endDate, setEndDate] = useState(todayStr);
  const [view, setView] = useState("monthly");
  const [tab, setTab] = useState("temp");
  const [downloading, setDownloading] = useState(false);

  const years = ["2019","2020","2021","2022","2023","2024","2025","2026"];
  const currentYear = new Date().getFullYear().toString();

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true); setError(null);
      try {
        const url = `https://archive-api.open-meteo.com/v1/archive?latitude=${KHULNA_LAT}&longitude=${KHULNA_LON}&start_date=2019-01-01&end_date=${todayStr}&daily=temperature_2m_max,temperature_2m_min,temperature_2m_mean,relative_humidity_2m_mean,shortwave_radiation_sum&timezone=Asia%2FDhaka`;
        const res = await fetch(url);
        const json = await res.json();
        setRawData(json);
      } catch (e) {
        setError("Failed to fetch weather data.");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const allDailyRows = useMemo(() => {
    if (!rawData) return [];
    return rawData.daily.time.map((d, i) => ({
      date: d,
      maxTemp: rawData.daily.temperature_2m_max[i],
      minTemp: rawData.daily.temperature_2m_min[i],
      meanTemp: rawData.daily.temperature_2m_mean[i],
      humidity: rawData.daily.relative_humidity_2m_mean[i],
      solar: rawData.daily.shortwave_radiation_sum[i],
    }));
  }, [rawData]);

  const filteredRows = useMemo(() => {
    return allDailyRows.filter(r => r.date >= startDate && r.date <= endDate);
  }, [allDailyRows, startDate, endDate]);

  const monthlyData = useMemo(() => groupByMonth(filteredRows), [filteredRows]);
  const chartData = view === "monthly" ? monthlyData : filteredRows.map(r => ({ ...r, label: r.date.slice(5) }));

  const allTemps = filteredRows.map(r => r.meanTemp).filter(v => v != null);
  const allHum   = filteredRows.map(r => r.humidity).filter(v => v != null);
  const allMax   = filteredRows.map(r => r.maxTemp).filter(v => v != null);
  const allMin   = filteredRows.map(r => r.minTemp).filter(v => v != null);
  const allSolar = filteredRows.map(r => r.solar).filter(v => v != null);

  const statCards = [
    { label:"Avg Temperature",  value: avg(allTemps) != null ? avg(allTemps)+"°C"    : "—", icon:"🌡️", color:"#fb923c" },
    { label:"Avg Humidity",     value: avg(allHum)   != null ? avg(allHum)+"%"        : "—", icon:"💧", color:"#38bdf8" },
    { label:"Peak Max Temp",    value: allMax.length  ? Math.max(...allMax).toFixed(1)+"°C" : "—", icon:"🔥", color:"#f87171" },
    { label:"Avg Solar Radiation", value: avg(allSolar) != null ? avg(allSolar)+" MJ/m²" : "—", icon:"☀️", color:"#fbbf24" },
  ];

  const setYear = (y) => {
    setStartDate(`${y}-01-01`);
    setEndDate(y === currentYear ? todayStr : `${y}-12-31`);
  };
  const setAllTime = () => { setStartDate("2019-01-01"); setEndDate(todayStr); };

  const isAllTime = startDate === "2019-01-01" && endDate === todayStr;
  const isYear = (y) => startDate === `${y}-01-01` && (endDate === `${y}-12-31` || (y === currentYear && endDate === todayStr));

  const downloadExcel = () => {
    setDownloading(true);
    try {
      const wb = XLSX.utils.book_new();

      // Sheet 1: Daily Data
      const ws1 = XLSX.utils.aoa_to_sheet([
        ["Date", "Max Temp (°C)", "Min Temp (°C)", "Mean Temp (°C)", "Humidity (%)", "Solar Radiation (MJ/m²)"],
        ...filteredRows.map(r => [r.date, r.maxTemp, r.minTemp, r.meanTemp, r.humidity, r.solar])
      ]);
      ws1["!cols"] = [{ wch:14 },{ wch:16 },{ wch:16 },{ wch:17 },{ wch:14 },{ wch:22 }];
      XLSX.utils.book_append_sheet(wb, ws1, "Daily Data");

      // Sheet 2: Monthly Averages
      const ws2 = XLSX.utils.aoa_to_sheet([
        ["Month", "Avg Max Temp (°C)", "Avg Min Temp (°C)", "Avg Mean Temp (°C)", "Avg Humidity (%)", "Avg Solar Radiation (MJ/m²)"],
        ...monthlyData.map(m => [m.label, m.maxTemp, m.minTemp, m.meanTemp, m.humidity, m.solar])
      ]);
      ws2["!cols"] = [{ wch:14 },{ wch:18 },{ wch:18 },{ wch:20 },{ wch:18 },{ wch:26 }];
      XLSX.utils.book_append_sheet(wb, ws2, "Monthly Averages");

      // Sheet 3: Summary
      const ws3 = XLSX.utils.aoa_to_sheet([
        ["Metric", "Value"],
        ["Data Range", `${startDate} to ${endDate}`],
        ["Total Days", filteredRows.length],
        ["Average Mean Temp (°C)", avg(allTemps)],
        ["Average Humidity (%)", avg(allHum)],
        ["Highest Max Temp (°C)", allMax.length ? Math.max(...allMax).toFixed(1) : "—"],
        ["Lowest Min Temp (°C)", allMin.length ? Math.min(...allMin).toFixed(1) : "—"],
        ["Highest Humidity (%)", allHum.length ? Math.max(...allHum).toFixed(0) : "—"],
        ["Lowest Humidity (%)", allHum.length ? Math.min(...allHum).toFixed(0) : "—"],
        ["Avg Solar Radiation (MJ/m²)", avg(allSolar)],
        ["Max Solar Radiation (MJ/m²)", allSolar.length ? Math.max(...allSolar).toFixed(1) : "—"],
        ["",""],
        ["Source", "Open-Meteo Historical Weather Archive"],
        ["Dataset", "ERA5 Reanalysis (ECMWF)"],
        ["Location", `Khulna, Bangladesh (${KHULNA_LAT}°N, ${KHULNA_LON}°E)`],
        ["Downloaded on", new Date().toLocaleDateString()],
        ["Citation", "Hersbach et al. (2020), QJRMS. doi:10.1002/qj.3803"],
      ]);
      ws3["!cols"] = [{ wch:28 },{ wch:38 }];
      XLSX.utils.book_append_sheet(wb, ws3, "Summary & Citation");

      XLSX.writeFile(wb, `Khulna_Weather_${startDate}_to_${endDate}.xlsx`);
    } catch(e) {
      alert("Download failed: " + e.message);
    } finally {
      setDownloading(false);
    }
  };

  const box = { background:"rgba(255,255,255,0.03)", border:"1px solid #102d4a", borderRadius:16, padding:"22px 16px 16px", marginBottom:18 };

  return (
    <div style={{ minHeight:"100vh", background:"linear-gradient(160deg,#050e1a 0%,#071a2e 40%,#0a2440 100%)", fontFamily:"Georgia,serif", color:"#cce8f8", paddingBottom:48 }}>

      {/* HEADER */}
      <div style={{ padding:"24px 28px 16px", borderBottom:"1px solid #0f3455", background:"rgba(0,0,0,0.3)", backdropFilter:"blur(8px)", position:"sticky", top:0, zIndex:10 }}>
        <div style={{ maxWidth:1000, margin:"0 auto", display:"flex", alignItems:"center", justifyContent:"space-between", flexWrap:"wrap", gap:12 }}>
          <div>
            <div style={{ fontSize:10, letterSpacing:4, color:"#38bdf8", textTransform:"uppercase", marginBottom:2 }}>Bangladesh · 22.81°N 89.56°E</div>
            <h1 style={{ margin:0, fontSize:26, fontWeight:700, color:"#e0f4ff", letterSpacing:-0.5 }}>Khulna Weather Archive</h1>
            <div style={{ fontSize:12, color:"#64a7c8", marginTop:2 }}>Temperature & Humidity · ERA5 Reanalysis · 2019–Present</div>
          </div>
          <button onClick={downloadExcel} disabled={downloading || !filteredRows.length} style={{
            display:"flex", alignItems:"center", gap:8, padding:"10px 20px", borderRadius:10,
            border:"1px solid #0ea5e9", background: downloading ? "#062236" : "linear-gradient(135deg,#0c3a5e,#0e4a78)",
            color:"#7dd3fc", cursor: downloading || !filteredRows.length ? "not-allowed" : "pointer",
            fontSize:14, fontFamily:"Georgia,serif", fontWeight:600,
            boxShadow:"0 2px 12px rgba(14,165,233,0.2)", opacity: !filteredRows.length ? 0.5 : 1
          }}>
            <span style={{ fontSize:18 }}>📥</span>
            {downloading ? "Exporting…" : `Download Excel (${filteredRows.length.toLocaleString()} days)`}
          </button>
        </div>
      </div>

      <div style={{ maxWidth:1000, margin:"0 auto", padding:"0 18px" }}>

        {/* DATE RANGE FILTER */}
        <div style={{ ...box, marginTop:22, padding:"20px 22px" }}>
          <div style={{ fontSize:11, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase", marginBottom:14 }}>📅 Filter by Date Range</div>
          <div style={{ display:"flex", flexWrap:"wrap", gap:14, alignItems:"flex-end" }}>
            <div>
              <div style={{ fontSize:11, color:"#4a8aaa", marginBottom:5 }}>START DATE</div>
              <input type="date" value={startDate} min="2019-01-01" max={endDate}
                onChange={e => setStartDate(e.target.value)} style={inputStyle} />
            </div>
            <div style={{ color:"#1e4d6b", fontSize:20, paddingBottom:4 }}>→</div>
            <div>
              <div style={{ fontSize:11, color:"#4a8aaa", marginBottom:5 }}>END DATE</div>
              <input type="date" value={endDate} min={startDate} max={todayStr}
                onChange={e => setEndDate(e.target.value)} style={inputStyle} />
            </div>
            <div style={{ width:1, height:38, background:"#0f3455", alignSelf:"center" }} />
            <div>
              <div style={{ fontSize:11, color:"#4a8aaa", marginBottom:5 }}>QUICK SELECT</div>
              <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                <button onClick={setAllTime} style={btnStyle(isAllTime)}>All</button>
                {years.map(y => (
                  <button key={y} onClick={() => setYear(y)} style={btnStyle(isYear(y))}>{y}</button>
                ))}
              </div>
            </div>
          </div>
          {filteredRows.length > 0 && (
            <div style={{ marginTop:10, fontSize:12, color:"#4a8aaa" }}>
              Showing <b style={{ color:"#7dd3fc" }}>{filteredRows.length.toLocaleString()} days</b> · <b style={{ color:"#7dd3fc" }}>{startDate}</b> → <b style={{ color:"#7dd3fc" }}>{endDate}</b>
            </div>
          )}
        </div>

        {loading && (
          <div style={{ textAlign:"center", padding:"80px 0", color:"#38bdf8" }}>
            <div style={{ fontSize:48, marginBottom:14 }}>🌀</div>
            <div style={{ fontSize:15, letterSpacing:2 }}>Loading ERA5 weather archive…</div>
          </div>
        )}
        {error && (
          <div style={{ textAlign:"center", padding:"60px 0", color:"#f87171" }}>
            <div style={{ fontSize:32 }}>⚠️</div>
            <div style={{ marginTop:10 }}>{error}</div>
          </div>
        )}
        {!loading && !error && filteredRows.length === 0 && (
          <div style={{ textAlign:"center", padding:"60px 0", color:"#4a8aaa" }}>
            <div style={{ fontSize:32 }}>🔍</div>
            <div style={{ marginTop:10 }}>No data for selected date range.</div>
          </div>
        )}

        {!loading && !error && filteredRows.length > 0 && (
          <>
            {/* STAT CARDS */}
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(175px,1fr))", gap:12, marginBottom:18 }}>
              {statCards.map((s,i) => (
                <div key={i} style={{ background:"rgba(255,255,255,0.04)", border:"1px solid #102d4a", borderRadius:14, padding:"16px 18px" }}>
                  <div style={{ fontSize:20, marginBottom:6 }}>{s.icon}</div>
                  <div style={{ fontSize:22, fontWeight:700, color:s.color }}>{s.value}</div>
                  <div style={{ fontSize:11, color:"#64a7c8", marginTop:3 }}>{s.label}</div>
                </div>
              ))}
            </div>

            {/* VIEW & TAB CONTROLS */}
            <div style={{ display:"flex", gap:10, marginBottom:14, flexWrap:"wrap", alignItems:"center", justifyContent:"space-between" }}>
              <div style={{ display:"flex", gap:3, background:"rgba(255,255,255,0.04)", borderRadius:10, padding:4, border:"1px solid #0f3455" }}>
                {[["monthly","Monthly Avg"],["daily","Daily View"]].map(([v,l]) => (
                  <button key={v} onClick={() => setView(v)} style={{ padding:"6px 16px", borderRadius:7, border:"none", background:view===v?"#0c3a5e":"transparent", color:view===v?"#7dd3fc":"#4a8aaa", cursor:"pointer", fontSize:13, fontFamily:"inherit" }}>{l}</button>
                ))}
              </div>
              <div style={{ display:"flex", gap:3, background:"rgba(255,255,255,0.04)", borderRadius:10, padding:4, border:"1px solid #0f3455" }}>
                {[["temp","🌡️ Temperature"],["humidity","💧 Humidity"],["solar","☀️ Solar"],["both","⚡ All"]].map(([v,l]) => (
                  <button key={v} onClick={() => setTab(v)} style={{ padding:"6px 14px", borderRadius:7, border:"none", background:tab===v?"#0c3a5e":"transparent", color:tab===v?"#7dd3fc":"#4a8aaa", cursor:"pointer", fontSize:12, fontFamily:"inherit" }}>{l}</button>
                ))}
              </div>
            </div>

            {/* TEMPERATURE CHART */}
            {(tab==="temp"||tab==="both") && (
              <div style={box}>
                <div style={{ paddingLeft:8, marginBottom:12 }}>
                  <div style={{ fontSize:11, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase" }}>Surface Temperature</div>
                  <div style={{ fontSize:16, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>{view==="monthly" ? "Monthly Averages" : "Daily Records"}</div>
                </div>
                <ResponsiveContainer width="100%" height={270}>
                  {view === "monthly" ? (
                    <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                      <defs>
                        <linearGradient id="gMax" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#f97316" stopOpacity={0.3}/><stop offset="95%" stopColor="#f97316" stopOpacity={0}/>
                        </linearGradient>
                        <linearGradient id="gMin" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#38bdf8" stopOpacity={0.2}/><stop offset="95%" stopColor="#38bdf8" stopOpacity={0}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3"/>
                      <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={Math.max(0,Math.floor(monthlyData.length/12)-1)}/>
                      <YAxis tick={{ fill:"#4a8aaa", fontSize:11 }} unit="°C" domain={[10,42]}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <Legend wrapperStyle={{ color:"#7dd3fc", fontSize:12 }}/>
                      <Area type="monotone" dataKey="maxTemp" name="Max Temp" stroke="#f97316" fill="url(#gMax)" strokeWidth={2} dot={false} unit="°C"/>
                      <Area type="monotone" dataKey="meanTemp" name="Mean Temp" stroke="#facc15" fill="none" strokeWidth={1.5} dot={false} unit="°C" strokeDasharray="4 2"/>
                      <Area type="monotone" dataKey="minTemp" name="Min Temp" stroke="#38bdf8" fill="url(#gMin)" strokeWidth={2} dot={false} unit="°C"/>
                    </AreaChart>
                  ) : (
                    <ComposedChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3"/>
                      <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={Math.max(0,Math.floor(filteredRows.length/12)-1)}/>
                      <YAxis tick={{ fill:"#4a8aaa", fontSize:11 }} unit="°C" domain={[10,45]}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <Legend wrapperStyle={{ color:"#7dd3fc", fontSize:12 }}/>
                      <Area type="monotone" dataKey="maxTemp" name="Max Temp" stroke="#f97316" fill="#f9731618" strokeWidth={1.5} dot={false} unit="°C"/>
                      <Area type="monotone" dataKey="minTemp" name="Min Temp" stroke="#38bdf8" fill="#38bdf818" strokeWidth={1.5} dot={false} unit="°C"/>
                    </ComposedChart>
                  )}
                </ResponsiveContainer>
              </div>
            )}

            {/* HUMIDITY CHART */}
            {(tab==="humidity"||tab==="both") && (
              <div style={box}>
                <div style={{ paddingLeft:8, marginBottom:12 }}>
                  <div style={{ fontSize:11, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase" }}>Relative Humidity</div>
                  <div style={{ fontSize:16, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>{view==="monthly" ? "Monthly Averages" : "Daily Records"}</div>
                </div>
                <ResponsiveContainer width="100%" height={240}>
                  {view === "monthly" ? (
                    <BarChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3"/>
                      <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={Math.max(0,Math.floor(monthlyData.length/12)-1)}/>
                      <YAxis tick={{ fill:"#4a8aaa", fontSize:11 }} unit="%" domain={[40,100]}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <ReferenceLine y={80} stroke="#7dd3fc" strokeDasharray="4 2" label={{ value:"Monsoon ~80%", fill:"#7dd3fc", fontSize:10, position:"insideTopLeft" }}/>
                      <Bar dataKey="humidity" name="Avg Humidity" fill="#0ea5e9" radius={[4,4,0,0]} unit="%"/>
                    </BarChart>
                  ) : (
                    <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                      <defs>
                        <linearGradient id="gHum" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.4}/><stop offset="95%" stopColor="#0ea5e9" stopOpacity={0.05}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3"/>
                      <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={Math.max(0,Math.floor(filteredRows.length/12)-1)}/>
                      <YAxis tick={{ fill:"#4a8aaa", fontSize:11 }} unit="%" domain={[30,100]}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <ReferenceLine y={80} stroke="#7dd3fc" strokeDasharray="4 2"/>
                      <Area type="monotone" dataKey="humidity" name="Humidity" stroke="#0ea5e9" fill="url(#gHum)" strokeWidth={1.5} dot={false} unit="%"/>
                    </AreaChart>
                  )}
                </ResponsiveContainer>
              </div>
            )}

            {/* SOLAR RADIATION CHART */}
            {(tab==="solar"||tab==="both") && (
              <div style={box}>
                <div style={{ paddingLeft:8, marginBottom:12 }}>
                  <div style={{ fontSize:11, color:"#fbbf24", letterSpacing:3, textTransform:"uppercase" }}>Solar Radiation</div>
                  <div style={{ fontSize:16, fontWeight:700, color:"#e0f4ff", marginTop:3 }}>
                    {view==="monthly" ? "Monthly Avg Daily Radiation" : "Daily Shortwave Radiation"} · MJ/m²
                  </div>
                </div>
                <ResponsiveContainer width="100%" height={240}>
                  {view === "monthly" ? (
                    <BarChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3"/>
                      <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={Math.max(0,Math.floor(monthlyData.length/12)-1)}/>
                      <YAxis tick={{ fill:"#4a8aaa", fontSize:11 }} unit=" MJ" domain={[0, 30]}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <ReferenceLine y={20} stroke="#fbbf24" strokeDasharray="4 2" label={{ value:"High radiation ~20 MJ/m²", fill:"#fbbf24", fontSize:10, position:"insideTopLeft" }}/>
                      <Bar dataKey="solar" name="Solar Radiation" fill="#f59e0b" radius={[4,4,0,0]} unit=" MJ/m²"/>
                    </BarChart>
                  ) : (
                    <AreaChart data={chartData} margin={{ top:5, right:16, left:0, bottom:5 }}>
                      <defs>
                        <linearGradient id="gSol" x1="0" y1="0" x2="0" y2="1">
                          <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.45}/><stop offset="95%" stopColor="#f59e0b" stopOpacity={0.03}/>
                        </linearGradient>
                      </defs>
                      <CartesianGrid stroke="#0f3050" strokeDasharray="3 3"/>
                      <XAxis dataKey="label" tick={{ fill:"#4a8aaa", fontSize:10 }} interval={Math.max(0,Math.floor(filteredRows.length/12)-1)}/>
                      <YAxis tick={{ fill:"#4a8aaa", fontSize:11 }} unit=" MJ" domain={[0,35]}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <Area type="monotone" dataKey="solar" name="Solar Radiation" stroke="#f59e0b" fill="url(#gSol)" strokeWidth={1.5} dot={false} unit=" MJ/m²"/>
                    </AreaChart>
                  )}
                </ResponsiveContainer>
                <div style={{ paddingLeft:8, marginTop:8, fontSize:11, color:"#6b7280", fontStyle:"italic" }}>
                  Shortwave radiation sum (direct + diffuse) · Higher in pre-monsoon (Mar–May), lower during monsoon cloud cover (Jun–Sep)
                </div>
              </div>
            )}

            {/* SEASONAL CARDS */}
            <div style={box}>
              <div style={{ fontSize:11, color:"#38bdf8", letterSpacing:3, textTransform:"uppercase", marginBottom:14 }}>Seasonal Patterns — Khulna</div>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(185px,1fr))", gap:10 }}>
                {[
                  { season:"☁️ Monsoon",      months:"Jun – Sep", temp:"29–33°C", hum:"80–90%", note:"Peak humidity & rainfall" },
                  { season:"🌸 Pre-monsoon",   months:"Mar – May", temp:"33–36°C", hum:"60–75%", note:"Hottest period of year" },
                  { season:"🍂 Post-monsoon",  months:"Oct – Nov", temp:"28–32°C", hum:"70–80%", note:"Cooling with late rains" },
                  { season:"❄️ Winter",        months:"Dec – Feb", temp:"15–27°C", hum:"55–70%", note:"Driest & coolest season" },
                ].map((s,i) => (
                  <div key={i} style={{ background:"rgba(14,165,233,0.06)", border:"1px solid #0c3a5e", borderRadius:12, padding:"13px 15px" }}>
                    <div style={{ fontSize:13, fontWeight:700, color:"#7dd3fc", marginBottom:4 }}>{s.season}</div>
                    <div style={{ fontSize:11, color:"#4a8aaa", marginBottom:7 }}>{s.months}</div>
                    <div style={{ fontSize:12, color:"#e0f4ff", marginBottom:2 }}>🌡️ {s.temp}</div>
                    <div style={{ fontSize:12, color:"#e0f4ff", marginBottom:7 }}>💧 {s.hum}</div>
                    <div style={{ fontSize:11, color:"#64a7c8", fontStyle:"italic" }}>{s.note}</div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{ textAlign:"center", fontSize:11, color:"#2a5a7a" }}>
              Data: Open-Meteo Archive · ERA5 Reanalysis (ECMWF) · Cite: Hersbach et al. (2020), QJRMS · doi:10.1002/qj.3803
            </div>
          </>
        )}
      </div>
    </div>
  );
}
